// Code generated by selo gen --lang rust. DO NOT EDIT.

use crate::data::CPF_REGIONS;
use crate::mod11::{self, CheckDigit, Rule, SeloError};

const DV1: CheckDigit = CheckDigit { weights: &[10, 9, 8, 7, 6, 5, 4, 3, 2], rule: Rule::ModRemainder, remainder_to0: &[10, 11], multiply_by10: true, encode_x_at: 0, encode_zero_at: 0 };
const DV2: CheckDigit = CheckDigit { weights: &[11, 10, 9, 8, 7, 6, 5, 4, 3, 2], rule: Rule::ModRemainder, remainder_to0: &[10, 11], multiply_by10: true, encode_x_at: 0, encode_zero_at: 0 };

fn to_ints(d: &str) -> Vec<i32> {
    d.bytes().map(|c| (c - b'0') as i32).collect()
}

/// Report whether value is a valid CPF (formatted or not).
pub fn validate_cpf(value: &str) -> bool {
    let d = mod11::only_digits(value);
    if d.len() != 11 {
        return false;
    }
    if mod11::all_equal(&d) {
        return false;
    }
    let digits = to_ints(&d);
    let dv1 = mod11::compute_digit(mod11::weighted_sum(&digits[0..9], DV1.weights, false), &DV1);
    let dv2 = mod11::compute_digit(mod11::weighted_sum(&digits[0..10], DV2.weights, false), &DV2);
    dv1 == digits[9] && dv2 == digits[10]
}

/// Render value as XXX.XXX.XXX-XX, or return an error on bad length.
pub fn format_cpf(value: &str) -> Result<String, SeloError> {
    let d = mod11::only_digits(value);
    if d.len() != 11 {
        return Err(SeloError::InvalidLength);
    }
    Ok(format!("{}.{}.{}-{}", &d[0..3], &d[3..6], &d[6..9], &d[9..11]))
}

/// Return the issuing region from the 9th digit, or an error.
pub fn origin_cpf(value: &str) -> Result<String, SeloError> {
    let d = mod11::only_digits(value);
    if d.len() < 9 {
        return Err(SeloError::InvalidLength);
    }
    let key = (d.as_bytes()[8] - b'0') as i32;
    match CPF_REGIONS.iter().find(|(k, _)| *k == key).map(|(_, v)| *v) {
        Some(region) => Ok(region.to_string()),
        None => Err(SeloError::InvalidLength),
    }
}

/// Return a random, valid CPF (unformatted, 11 digits).
pub fn generate_cpf() -> String {
    loop {
        let mut number: Vec<i32> = Vec::with_capacity(11);
        for _ in 0..9 {
            number.push(mod11::rand_int(9) as i32);
        }
        number.push(mod11::compute_digit(mod11::weighted_sum(&number, DV1.weights, false), &DV1));
        number.push(mod11::compute_digit(mod11::weighted_sum(&number, DV2.weights, false), &DV2));
        let out: String = number.iter().map(|n| n.to_string()).collect();
        if !mod11::all_equal(&out) {
            return out;
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn vector() -> serde_json::Value {
        let p = concat!(env!("CARGO_MANIFEST_DIR"), "/vectors/cpf.json");
        let s = std::fs::read_to_string(p).expect("read vector");
        serde_json::from_str(&s).expect("parse vector")
    }

    #[test]
    fn validate_cases() {
        for case in vector()["validate"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let valid = case["valid"].as_bool().unwrap();
            assert_eq!(valid, validate_cpf(input), "validate {}", input);
        }
    }

    #[test]
    fn format_cases() {
        for case in vector()["format"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let is_error = case
                .get("error")
                .and_then(|e| e.as_str())
                .map(|e| !e.is_empty())
                .unwrap_or(false);
            if is_error {
                assert!(format_cpf(input).is_err(), "format expected err {}", input);
            } else {
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, format_cpf(input).unwrap(), "format {}", input);
            }
        }
    }

    #[test]
    fn origin_cases() {
        if let Some(arr) = vector().get("origin").and_then(|o| o.as_array()) {
            for case in arr {
                let input = case["input"].as_str().unwrap();
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, origin_cpf(input).unwrap(), "origin {}", input);
            }
        }
    }

    #[test]
    fn generate_round_trip() {
        for _ in 0..100 {
            let v = generate_cpf();
            assert!(validate_cpf(&v), "generate produced invalid: {}", v);
        }
    }
}
